#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Relieve write/lock contention (exit-0-safe): cap async lanes hard, trim crawler fleet
to 5, and terminate stuck idle-in-transaction backends holding locks. Reports before/after
active-conn counts + the top blocking query."""
import os,sys,json,time,subprocess
def sh(c,t=30):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=20):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return r.stdout.strip() if r.returncode==0 else "ERR"
out={"kind":"relieve","ts":int(time.time())}
try:
    out["active_before"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["idle_in_txn"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='idle in transaction'")
    out["top_blockers"]=psql("SELECT pid||':'||state||':'||round(extract(epoch from now()-state_change))||'s:'||left(regexp_replace(query,'\\s+',' ','g'),60) FROM pg_stat_activity WHERE state IN ('active','idle in transaction') AND now()-state_change>interval '30s' ORDER BY state_change LIMIT 6")
    # 1) terminate stuck idle-in-transaction (>90s) -> releases their locks
    out["terminated_idle"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE state='idle in transaction' AND now()-state_change>interval '90s') x")
    # 2) cap async hard
    for base in ["atlas-enrich-async","atlas-enrich-async-batch"]:
        dd="/etc/systemd/system/%s@.service.d"%base; os.makedirs(dd,exist_ok=True)
        open(dd+"/override.conf","w").write("[Service]\nEnvironment=ATLAS_ASYNC_LANES=100\nEnvironment=ATLAS_ASYNC_PG_POOL=6\nEnvironment=ATLAS_ASYNC_DB_WRITERS=4\n")
    sh("systemctl daemon-reload 2>&1")
    out["async_restart"]=sh("systemctl restart atlas-enrich-async@1.service atlas-enrich-async-batch@1.service 2>&1; echo rc=$?")
    # 3) trim crawler fleet 10 -> 5
    out["crawler_trim"]=sh("for i in 6 7 8 9 10; do systemctl disable --now atlas-deepcrawl-pool@$i.service 2>/dev/null; done; systemctl list-units 'atlas-deepcrawl-pool@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
    time.sleep(12)
    out["active_after"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["total_after"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/relieve.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"relieve","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
